SELECT pi.product_id, p.product_name, p.unit, pi.lot_no, GREATEST( pi.inbound_qty - IFNULL(( SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no ), 0), 0 ) AS stock_qty, 50 AS safe_qty, pi.reg_date, pi.expire_date FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
AND ( pi.inbound_qty - IFNULL((SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no), 0)
- IFNULL((SELECT SUM(sr.reserved_qty) FROM stock_reservation sr WHERE sr.product_id = pi.product_id AND sr.lot_no = pi.lot_no), 0) ) > 0
AND ( pi.inbound_qty - IFNULL((SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no), 0)
- IFNULL((SELECT SUM(sr.reserved_qty) FROM stock_reservation sr WHERE sr.product_id = pi.product_id AND sr.lot_no = pi.lot_no), 0) ) = 0
ORDER BY pi.reg_date DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM ( SELECT pi.product_id, pi.lot_no, ( pi.inbound_qty - IFNULL(( SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no ), 0) + IFNULL(( SELECT SUM(pt.qty) FROM product_transaction pt WHERE pt.product_id = pi.product_id AND pt.lot_no = pi.lot_no AND pt.type = '취소' ), 0) - IFNULL(( SELECT SUM(sr.reserved_qty) FROM stock_reservation sr WHERE sr.product_id = pi.product_id AND sr.lot_no = pi.lot_no ), 0) ) AS stock_qty FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
) AS tmp
stock_qty > 0
stock_qty = 0

