SELECT '입고' AS type, pi.inbound_qty AS qty, pi.reg_date AS regDate, '오더브릿지' AS clientName, '' AS memo, pi.inbound_id AS inboundId, NULL AS outboundId, NULL AS clOrderId FROM product_inbound pi WHERE pi.lot_no = #{lotNo}
UNION ALL
SELECT DISTINCT '출고' AS type, po.outbound_qty AS qty, po.outbound_date AS regDate, c.client_name AS clientName, '' AS memo, NULL AS inboundId, po.outbound_id AS outboundId, ( SELECT MIN(cd.cl_order_id) FROM client_delivery cd WHERE cd.tracking_number = po.tracking_number ) AS clOrderId FROM product_outbound po LEFT JOIN client c ON po.client_id = c.client_id WHERE po.lot_no = #{lotNo}
UNION ALL
SELECT '취소' AS type, pt.qty AS qty, pt.reg_date AS regDate, c2.client_name AS clientName, '' AS memo, NULL AS inboundId, pt.outbound_id AS outboundId, COALESCE(pt.cl_order_id, cd2.cl_order_id) AS clOrderId FROM product_transaction pt LEFT JOIN product_outbound po2 ON pt.outbound_id = po2.outbound_id LEFT JOIN client_delivery cd2 ON cd2.tracking_number = po2.tracking_number LEFT JOIN client c2 ON COALESCE(pt.client_id, po2.client_id) = c2.client_id WHERE pt.lot_no = #{lotNo} AND pt.type = '취소'
ORDER BY regDate ASC

SELECT COALESCE(SUM(reserved_qty), 0)
FROM stock_reservation
WHERE product_id = #{productId} AND lot_no = #{lotNo}

